export enum TokenType {
  QUERY = 'QUERY',
  ENCODE = 'ENCODE',
  FORK = 'FORK',
  WEIGHT = 'WEIGHT',
  ENSEMBLE = 'ENSEMBLE',
  CRITIQUE = 'CRITIQUE',
  SAMPLE = 'SAMPLE',
  DETOKENIZE = 'DETOKENIZE',

  NUMBER = 'NUMBER',
  STRING = 'STRING',
  IDENT = 'IDENT',

  LPAREN = 'LPAREN',
  RPAREN = 'RPAREN',
  LBRACE = 'LBRACE',
  RBRACE = 'RBRACE',
  LBRACKET = 'LBRACKET',
  RBRACKET = 'RBRACKET',

  ARROW = 'ARROW',
  DOT = 'DOT',
  COMMA = 'COMMA',
  SEMICOLON = 'SEMICOLON',
  COLON = 'COLON',

  PLUS = 'PLUS',
  MINUS = 'MINUS',
  STAR = 'STAR',
  SLASH = 'SLASH',
  PERCENT = 'PERCENT',

  EQUALS = 'EQUALS',
  LPIPE = 'LPIPE',
  RPIPE = 'RPIPE',

  EOF = 'EOF',
  UNKNOWN = 'UNKNOWN',
}

export interface Token {
  type: TokenType;
  value: string | number;
  line: number;
  column: number;
}

export class Lexer {
  private source: string;
  private position: number;
  private line: number;
  private column: number;
  private tokens: Token[] = [];

  constructor(source: string) {
    this.source = source;
    this.position = 0;
    this.line = 1;
    this.column = 1;
  }

  tokenize(): Token[] {
    while (this.position < this.source.length) {
      this.skipWhitespaceAndComments();
      if (this.position >= this.source.length) break;

      const char = this.source[this.position];

      if (this.isDigit(char)) {
        this.readNumber();
      } else if (this.isStringDelimiter(char)) {
        this.readString();
      } else if (this.isIdentifierStart(char)) {
        this.readIdentifierOrKeyword();
      } else if (char === '(') {
        this.addToken(TokenType.LPAREN, '(');
        this.advance();
      } else if (char === ')') {
        this.addToken(TokenType.RPAREN, ')');
        this.advance();
      } else if (char === '{') {
        this.addToken(TokenType.LBRACE, '{');
        this.advance();
      } else if (char === '}') {
        this.addToken(TokenType.RBRACE, '}');
        this.advance();
      } else if (char === '[') {
        this.addToken(TokenType.LBRACKET, '[');
        this.advance();
      } else if (char === ']') {
        this.addToken(TokenType.RBRACKET, ']');
        this.advance();
      } else if (char === '-' && this.peek() === '>') {
        this.addToken(TokenType.ARROW, '->');
        this.advance();
        this.advance();
      } else if (char === '.') {
        this.addToken(TokenType.DOT, '.');
        this.advance();
      } else if (char === ',') {
        this.addToken(TokenType.COMMA, ',');
        this.advance();
      } else if (char === ';') {
        this.addToken(TokenType.SEMICOLON, ';');
        this.advance();
      } else if (char === ':') {
        this.addToken(TokenType.COLON, ':');
        this.advance();
      } else if (char === '+') {
        this.addToken(TokenType.PLUS, '+');
        this.advance();
      } else if (char === '-') {
        this.addToken(TokenType.MINUS, '-');
        this.advance();
      } else if (char === '*') {
        this.addToken(TokenType.STAR, '*');
        this.advance();
      } else if (char === '/') {
        this.addToken(TokenType.SLASH, '/');
        this.advance();
      } else if (char === '%') {
        this.addToken(TokenType.PERCENT, '%');
        this.advance();
      } else if (char === '=') {
        this.addToken(TokenType.EQUALS, '=');
        this.advance();
      } else if (char === '|') {
        if (this.peek() === '<') {
          this.addToken(TokenType.LPIPE, '|<');
          this.advance();
          this.advance();
        } else if (this.peek() === '>') {
          this.addToken(TokenType.RPIPE, '|>');
          this.advance();
          this.advance();
        } else {
          this.addToken(TokenType.UNKNOWN, char);
          this.advance();
        }
      } else {
        this.addToken(TokenType.UNKNOWN, char);
        this.advance();
      }
    }

    this.addToken(TokenType.EOF, '');
    return this.tokens;
  }

  private skipWhitespaceAndComments(): void {
    while (this.position < this.source.length) {
      const char = this.source[this.position];

      if (char === ' ' || char === '\t' || char === '\r') {
        this.advance();
      } else if (char === '\n') {
        this.line++;
        this.column = 1;
        this.position++;
      } else if (char === '#') {
        while (this.position < this.source.length && this.source[this.position] !== '\n') {
          this.advance();
        }
      } else {
        break;
      }
    }
  }

  private readNumber(): void {
    const startLine = this.line;
    const startColumn = this.column;
    let value = '';

    while (this.position < this.source.length && this.isDigit(this.source[this.position])) {
      value += this.source[this.position];
      this.advance();
    }

    if (this.source[this.position] === '.' && this.isDigit(this.source[this.position + 1])) {
      value += '.';
      this.advance();
      while (this.position < this.source.length && this.isDigit(this.source[this.position])) {
        value += this.source[this.position];
        this.advance();
      }
    }

    this.tokens.push({
      type: TokenType.NUMBER,
      value: parseFloat(value),
      line: startLine,
      column: startColumn,
    });
  }

  private readString(): void {
    const startLine = this.line;
    const startColumn = this.column;
    const delimiter = this.source[this.position];
    this.advance();

    let value = '';
    while (this.position < this.source.length && this.source[this.position] !== delimiter) {
      if (this.source[this.position] === '\\' && this.position + 1 < this.source.length) {
        this.advance();
        const nextChar = this.source[this.position];
        if (nextChar === 'n') value += '\n';
        else if (nextChar === 't') value += '\t';
        else if (nextChar === 'r') value += '\r';
        else if (nextChar === '\\') value += '\\';
        else if (nextChar === '"') value += '"';
        else if (nextChar === "'") value += "'";
        else value += nextChar;
      } else {
        value += this.source[this.position];
      }
      this.advance();
    }

    if (this.position < this.source.length) {
      this.advance();
    }

    this.tokens.push({
      type: TokenType.STRING,
      value,
      line: startLine,
      column: startColumn,
    });
  }

  private readIdentifierOrKeyword(): void {
    const startLine = this.line;
    const startColumn = this.column;
    let value = '';

    while (
      this.position < this.source.length &&
      (this.isIdentifierChar(this.source[this.position]) || this.isDigit(this.source[this.position]))
    ) {
      value += this.source[this.position];
      this.advance();
    }

    const keywordMap: { [key: string]: TokenType } = {
      query: TokenType.QUERY,
      encode: TokenType.ENCODE,
      fork: TokenType.FORK,
      weight: TokenType.WEIGHT,
      ensemble: TokenType.ENSEMBLE,
      critique: TokenType.CRITIQUE,
      sample: TokenType.SAMPLE,
      detokenize: TokenType.DETOKENIZE,
    };

    const type = keywordMap[value] || TokenType.IDENT;
    this.tokens.push({
      type,
      value,
      line: startLine,
      column: startColumn,
    });
  }

  private addToken(type: TokenType, value: string | number): void {
    this.tokens.push({
      type,
      value,
      line: this.line,
      column: this.column,
    });
  }

  private advance(): void {
    this.column++;
    this.position++;
  }

  private peek(): string {
    if (this.position + 1 >= this.source.length) return '\0';
    return this.source[this.position + 1];
  }

  private isDigit(char: string): boolean {
    return char >= '0' && char <= '9';
  }

  private isIdentifierStart(char: string): boolean {
    return (char >= 'a' && char <= 'z') || (char >= 'A' && char <= 'Z') || char === '_';
  }

  private isIdentifierChar(char: string): boolean {
    return this.isIdentifierStart(char);
  }

  private isStringDelimiter(char: string): boolean {
    return char === '"' || char === "'";
  }
}

export function createLexer(source: string): Lexer {
  return new Lexer(source);
}

export type NodeId = string | number;

export interface BaseNode {
  id: NodeId;
  nodeType: string;
  line?: number;
  column?: number;
}

export interface QueryNode extends BaseNode {
  nodeType: 'QueryNode';
  varName: string;
  embedding?: number[];
  semanticContent?: string;
  confidence?: number;
}

export interface EncodeNode extends BaseNode {
  nodeType: 'EncodeNode';
  inputVar: string;
  outputVar: string;
  latentDim?: number;
}

export interface PathNode extends BaseNode {
  nodeType: 'PathNode';
  pathType: 'analytical' | 'creative' | 'empirical';
  inputVar: string;
  outputVar: string;
}

export interface WeightNode extends BaseNode {
  nodeType: 'WeightNode';
  inputVar: string;
  weights?: {
    alpha: number;
    beta: number;
    gamma: number;
  };
}

export interface EnsembleNode extends BaseNode {
  nodeType: 'EnsembleNode';
  pathVars: [string, string, string];
  weightsVar: string;
  outputVar: string;
}

export interface CritiqueNode extends BaseNode {
  nodeType: 'CritiqueNode';
  inputVar: string;
  outputVar: string;
  confidenceThreshold?: number;
}

export interface SampleNode extends BaseNode {
  nodeType: 'SampleNode';
  inputVar: string;
  outputVar: string;
  threshold?: number;
  temperature?: number;
}

export interface DetokenizeNode extends BaseNode {
  nodeType: 'DetokenizeNode';
  inputVar: string;
  outputVar: string;
  language?: string;
}

export type ASTNode =
  | QueryNode
  | EncodeNode
  | PathNode
  | WeightNode
  | EnsembleNode
  | CritiqueNode
  | SampleNode
  | DetokenizeNode;

export interface Program {
  statements: ASTNode[];
}

export function getNodeType(node: ASTNode): string {
  return node.nodeType;
}

export function isQueryNode(node: ASTNode): node is QueryNode {
  return node.nodeType === 'QueryNode';
}

export function isEncodeNode(node: ASTNode): node is EncodeNode {
  return node.nodeType === 'EncodeNode';
}

export function isPathNode(node: ASTNode): node is PathNode {
  return node.nodeType === 'PathNode';
}

export function isWeightNode(node: ASTNode): node is WeightNode {
  return node.nodeType === 'WeightNode';
}

export function isEnsembleNode(node: ASTNode): node is EnsembleNode {
  return node.nodeType === 'EnsembleNode';
}

export function isCritiqueNode(node: ASTNode): node is CritiqueNode {
  return node.nodeType === 'CritiqueNode';
}

export function isSampleNode(node: ASTNode): node is SampleNode {
  return node.nodeType === 'SampleNode';
}

export function isDetokenizeNode(node: ASTNode): node is DetokenizeNode {
  return node.nodeType === 'DetokenizeNode';
}

export function createQueryNode(
  id: NodeId,
  varName: string,
  options?: Partial<QueryNode>
): QueryNode {
  return {
    id,
    nodeType: 'QueryNode',
    varName,
    ...options,
  };
}

export function createEncodeNode(
  id: NodeId,
  inputVar: string,
  outputVar: string,
  options?: Partial<EncodeNode>
): EncodeNode {
  return {
    id,
    nodeType: 'EncodeNode',
    inputVar,
    outputVar,
    ...options,
  };
}

export function createPathNode(
  id: NodeId,
  pathType: 'analytical' | 'creative' | 'empirical',
  inputVar: string,
  outputVar: string,
  options?: Partial<PathNode>
): PathNode {
  return {
    id,
    nodeType: 'PathNode',
    pathType,
    inputVar,
    outputVar,
    ...options,
  };
}

export function createWeightNode(
  id: NodeId,
  inputVar: string,
  options?: Partial<WeightNode>
): WeightNode {
  return {
    id,
    nodeType: 'WeightNode',
    inputVar,
    ...options,
  };
}

export function createEnsembleNode(
  id: NodeId,
  pathVars: [string, string, string],
  weightsVar: string,
  outputVar: string,
  options?: Partial<EnsembleNode>
): EnsembleNode {
  return {
    id,
    nodeType: 'EnsembleNode',
    pathVars,
    weightsVar,
    outputVar,
    ...options,
  };
}

export function createCritiqueNode(
  id: NodeId,
  inputVar: string,
  outputVar: string,
  options?: Partial<CritiqueNode>
): CritiqueNode {
  return {
    id,
    nodeType: 'CritiqueNode',
    inputVar,
    outputVar,
    ...options,
  };
}

export function createSampleNode(
  id: NodeId,
  inputVar: string,
  outputVar: string,
  options?: Partial<SampleNode>
): SampleNode {
  return {
    id,
    nodeType: 'SampleNode',
    inputVar,
    outputVar,
    ...options,
  };
}

export function createDetokenizeNode(
  id: NodeId,
  inputVar: string,
  outputVar: string,
  options?: Partial<DetokenizeNode>
): DetokenizeNode {
  return {
    id,
    nodeType: 'DetokenizeNode',
    inputVar,
    outputVar,
    ...options,
  };
}

export function printAST(node: ASTNode, depth: number = 0): string {
  const indent = '  '.repeat(depth);

  switch (node.nodeType) {
    case 'QueryNode': {
      const qn = node as QueryNode;
      return `${indent}QueryNode: ${qn.varName}`;
    }
    case 'EncodeNode': {
      const en = node as EncodeNode;
      return `${indent}EncodeNode: ${en.inputVar} -> ${en.outputVar}`;
    }
    case 'PathNode': {
      const pn = node as PathNode;
      return `${indent}PathNode(${pn.pathType}): ${pn.inputVar} -> ${pn.outputVar}`;
    }
    case 'WeightNode': {
      const wn = node as WeightNode;
      const weights = wn.weights
        ? ` [α=${wn.weights.alpha.toFixed(2)}, β=${wn.weights.beta.toFixed(2)}, γ=${wn.weights.gamma.toFixed(2)}]`
        : '';
      return `${indent}WeightNode: ${wn.inputVar}${weights}`;
    }
    case 'EnsembleNode': {
      const ens = node as EnsembleNode;
      return `${indent}EnsembleNode: (${ens.pathVars.join(', ')}) with ${ens.weightsVar} -> ${ens.outputVar}`;
    }
    case 'CritiqueNode': {
      const cn = node as CritiqueNode;
      return `${indent}CritiqueNode: ${cn.inputVar} -> ${cn.outputVar}`;
    }
    case 'SampleNode': {
      const sn = node as SampleNode;
      return `${indent}SampleNode: ${sn.inputVar} -> ${sn.outputVar}`;
    }
    case 'DetokenizeNode': {
      const dn = node as DetokenizeNode;
      return `${indent}DetokenizeNode: ${dn.inputVar} -> ${dn.outputVar}`;
    }
    default:
      return `${indent}UnknownNode`;
  }
}

export function printProgram(program: Program): string {
  return program.statements.map((node) => printAST(node, 0)).join('\n');
}

export function collectVariables(program: Program): Set<string> {
  const vars = new Set<string>();

  for (const node of program.statements) {
    switch (node.nodeType) {
      case 'QueryNode':
        vars.add((node as QueryNode).varName);
        break;
      case 'EncodeNode':
        vars.add((node as EncodeNode).outputVar);
        break;
      case 'PathNode':
        vars.add((node as PathNode).outputVar);
        break;
      case 'WeightNode':
        break;
      case 'EnsembleNode':
        vars.add((node as EnsembleNode).outputVar);
        break;
      case 'CritiqueNode':
        vars.add((node as CritiqueNode).outputVar);
        break;
      case 'SampleNode':
        vars.add((node as SampleNode).outputVar);
        break;
      case 'DetokenizeNode':
        vars.add((node as DetokenizeNode).outputVar);
        break;
    }
  }

  return vars;
}

export function getNodeInputVariables(node: ASTNode): string[] {
  switch (node.nodeType) {
    case 'QueryNode':
      return [];
    case 'EncodeNode':
      return [(node as EncodeNode).inputVar];
    case 'PathNode':
      return [(node as PathNode).inputVar];
    case 'WeightNode':
      return [(node as WeightNode).inputVar];
    case 'EnsembleNode': {
      const ens = node as EnsembleNode;
      return [...ens.pathVars, ens.weightsVar];
    }
    case 'CritiqueNode':
      return [(node as CritiqueNode).inputVar];
    case 'SampleNode':
      return [(node as SampleNode).inputVar];
    case 'DetokenizeNode':
      return [(node as DetokenizeNode).inputVar];
    default:
      return [];
  }
}

export function getNodeOutputVariable(node: ASTNode): string | null {
  switch (node.nodeType) {
    case 'QueryNode':
      return (node as QueryNode).varName;
    case 'EncodeNode':
      return (node as EncodeNode).outputVar;
    case 'PathNode':
      return (node as PathNode).outputVar;
    case 'WeightNode':
      return null;
    case 'EnsembleNode':
      return (node as EnsembleNode).outputVar;
    case 'CritiqueNode':
      return (node as CritiqueNode).outputVar;
    case 'SampleNode':
      return (node as SampleNode).outputVar;
    case 'DetokenizeNode':
      return (node as DetokenizeNode).outputVar;
    default:
      return null;
  }
}

import { Token, TokenType, Lexer } from './lexer';
import {
  Program,
  ASTNode,
  QueryNode,
  EncodeNode,
  PathNode,
  WeightNode,
  EnsembleNode,
  CritiqueNode,
  SampleNode,
  DetokenizeNode,
  createQueryNode,
  createEncodeNode,
  createPathNode,
  createWeightNode,
  createEnsembleNode,
  createCritiqueNode,
  createSampleNode,
  createDetokenizeNode,
} from './ast';

export class ParseError extends Error {
  constructor(message: string, token?: Token) {
    const loc = token ? ` at line ${token.line}, column ${token.column}` : '';
    super(`Parse error: ${message}${loc}`);
  }
}

export class Parser {
  private tokens: Token[];
  private position: number;
  private nodeIdCounter: number;

  constructor(tokens: Token[]) {
    this.tokens = tokens;
    this.position = 0;
    this.nodeIdCounter = 0;
  }

  parse(): Program {
    const statements: ASTNode[] = [];

    while (!this.isAtEnd()) {
      if (this.check(TokenType.EOF)) break;

      const stmt = this.parseStatement();
      if (stmt) {
        statements.push(stmt);
      }
    }

    return { statements };
  }

  private parseStatement(): ASTNode | null {
    if (this.match(TokenType.QUERY)) {
      return this.parseQuery();
    } else if (this.match(TokenType.ENCODE)) {
      return this.parseEncode();
    } else if (this.match(TokenType.FORK)) {
      return this.parseFork();
    } else if (this.match(TokenType.WEIGHT)) {
      return this.parseWeight();
    } else if (this.match(TokenType.ENSEMBLE)) {
      return this.parseEnsemble();
    } else if (this.match(TokenType.CRITIQUE)) {
      return this.parseCritique();
    } else if (this.match(TokenType.SAMPLE)) {
      return this.parseSample();
    } else if (this.match(TokenType.DETOKENIZE)) {
      return this.parseDetokenize();
    } else if (this.check(TokenType.SEMICOLON)) {
      this.advance();
      return null;
    } else {
      throw new ParseError(
        `Unexpected token: ${this.peek().value}`,
        this.peek()
      );
    }
  }

  private parseQuery(): QueryNode {
    const varName = this.expectIdentifier('variable name after query');
    this.consumeStatementEnd();

    const nodeId = this.nextNodeId();
    return createQueryNode(nodeId, varName);
  }

  private parseEncode(): EncodeNode {
    const inputVar = this.expectIdentifier('input variable for encode');
    this.expectArrow();
    const outputVar = this.expectIdentifier('output variable for encode');
    this.consumeStatementEnd();

    const nodeId = this.nextNodeId();
    return createEncodeNode(nodeId, inputVar, outputVar);
  }

  private parseFork(): ASTNode[] {
    const inputVar = this.expectIdentifier('input variable for fork');
    this.expectArrow();

    if (this.match(TokenType.LBRACE)) {
      const vars: string[] = [];

      vars.push(this.expectIdentifier('path variable in fork'));

      while (this.match(TokenType.COMMA)) {
        vars.push(this.expectIdentifier('path variable in fork'));
      }

      this.expect(TokenType.RBRACE, 'closing brace after path variables');

      if (vars.length !== 3) {
        throw new ParseError(`Fork must create exactly 3 paths, got ${vars.length}`);
      }

      this.consumeStatementEnd();

      const nodes: ASTNode[] = [];
      nodes.push(
        createPathNode(this.nextNodeId(), 'analytical', inputVar, vars[0])
      );
      nodes.push(
        createPathNode(this.nextNodeId(), 'creative', inputVar, vars[1])
      );
      nodes.push(
        createPathNode(this.nextNodeId(), 'empirical', inputVar, vars[2])
      );

      return nodes;
    } else {
      throw new ParseError('Expected { after fork arrow');
    }
  }

  private parseWeight(): WeightNode {
    let weights: { alpha: number; beta: number; gamma: number } | undefined;

    if (this.match(TokenType.LBRACKET)) {
      const alpha = this.expectNumber('weight alpha value');
      this.expect(TokenType.COMMA, 'comma between weights');
      const beta = this.expectNumber('weight beta value');
      this.expect(TokenType.COMMA, 'comma between weights');
      const gamma = this.expectNumber('weight gamma value');
      this.expect(TokenType.RBRACKET, 'closing bracket after weights');

      weights = { alpha, beta, gamma };
    }

    this.consumeStatementEnd();

    const nodeId = this.nextNodeId();
    return createWeightNode(nodeId, '', { weights });
  }

  private parseEnsemble(): EnsembleNode {
    const pathVar1 = this.expectIdentifier('first path variable for ensemble');
    const pathVar2 = this.expectIdentifier('second path variable for ensemble');
    const pathVar3 = this.expectIdentifier('third path variable for ensemble');

    this.expectArrow();

    const outputVar = this.expectIdentifier('output variable for ensemble');
    this.consumeStatementEnd();

    const nodeId = this.nextNodeId();
    return createEnsembleNode(nodeId, [pathVar1, pathVar2, pathVar3], 'weights', outputVar);
  }

  private parseCritique(): CritiqueNode {
    const inputVar = this.expectIdentifier('input variable for critique');
    this.expectArrow();
    const outputVar = this.expectIdentifier('output variable for critique');
    this.consumeStatementEnd();

    const nodeId = this.nextNodeId();
    return createCritiqueNode(nodeId, inputVar, outputVar);
  }

  private parseSample(): SampleNode {
    const inputVar = this.expectIdentifier('input variable for sample');
    let threshold: number | undefined;

    if (this.check(TokenType.NUMBER)) {
      threshold = this.expectNumber('sampling threshold');
    }

    this.expectArrow();

    const outputVar = this.expectIdentifier('output variable for sample');
    this.consumeStatementEnd();

    const nodeId = this.nextNodeId();
    return createSampleNode(nodeId, inputVar, outputVar, { threshold });
  }

  private parseDetokenize(): DetokenizeNode {
    const inputVar = this.expectIdentifier('input variable for detokenize');
    this.expectArrow();
    const outputVar = this.expectIdentifier('output variable for detokenize');
    this.consumeStatementEnd();

    const nodeId = this.nextNodeId();
    return createDetokenizeNode(nodeId, inputVar, outputVar);
  }

  private expectArrow(): void {
    this.expect(TokenType.ARROW, 'arrow (->)');
  }

  private expectIdentifier(context: string): string {
    if (!this.check(TokenType.IDENT)) {
      throw new ParseError(`Expected identifier ${context}, got ${this.peek().value}`);
    }
    const value = this.peek().value as string;
    this.advance();
    return value;
  }

  private expectNumber(context: string): number {
    if (!this.check(TokenType.NUMBER)) {
      throw new ParseError(`Expected number ${context}, got ${this.peek().value}`);
    }
    const value = this.peek().value as number;
    this.advance();
    return value;
  }

  private expect(type: TokenType, context: string): Token {
    if (!this.check(type)) {
      throw new ParseError(
        `Expected ${context}, got ${this.peek().value}`,
        this.peek()
      );
    }
    const token = this.peek();
    this.advance();
    return token;
  }

  private match(...types: TokenType[]): boolean {
    for (const type of types) {
      if (this.check(type)) {
        this.advance();
        return true;
      }
    }
    return false;
  }

  private check(type: TokenType): boolean {
    if (this.isAtEnd()) return false;
    return this.peek().type === type;
  }

  private advance(): Token {
    if (!this.isAtEnd()) this.position++;
    return this.previous();
  }

  private isAtEnd(): boolean {
    return this.peek().type === TokenType.EOF;
  }

  private peek(): Token {
    return this.tokens[this.position];
  }

  private previous(): Token {
    return this.tokens[this.position - 1];
  }

  private consumeStatementEnd(): void {
    if (this.match(TokenType.SEMICOLON)) {
      return;
    }
    if (this.check(TokenType.EOF) || this.isNewStatement()) {
      return;
    }
  }

  private isNewStatement(): boolean {
    const type = this.peek().type;
    return (
      type === TokenType.QUERY ||
      type === TokenType.ENCODE ||
      type === TokenType.FORK ||
      type === TokenType.WEIGHT ||
      type === TokenType.ENSEMBLE ||
      type === TokenType.CRITIQUE ||
      type === TokenType.SAMPLE ||
      type === TokenType.DETOKENIZE
    );
  }

  private nextNodeId(): number {
    return this.nodeIdCounter++;
  }
}

export function parse(source: string): Program {
  const lexer = new Lexer(source);
  const tokens = lexer.tokenize();
  const parser = new Parser(tokens);
  return parser.parse();
}

export function parseProgram(source: string): Program {
  return parse(source);
}

import { Program, ASTNode, getNodeInputVariables, getNodeOutputVariable } from './ast';
import {
  isQueryNode,
  isEncodeNode,
  isPathNode,
  isWeightNode,
  isEnsembleNode,
  isCritiqueNode,
  isSampleNode,
  isDetokenizeNode,
} from './ast';

export type MindLangType =
  | 'Query'
  | 'Latent'
  | 'Path'
  | 'Weight'
  | 'Ensemble'
  | 'Critique'
  | 'Output'
  | 'Unknown';

export interface TypeInfo {
  type: MindLangType;
  dimension?: number;
  constraints?: string[];
}

export class TypeError extends Error {
  constructor(message: string) {
    super(`Type error: ${message}`);
  }
}

export class Checker {
  private symbolTable: Map<string, TypeInfo>;
  private errors: string[];
  private warnings: string[];

  constructor() {
    this.symbolTable = new Map();
    this.errors = [];
    this.warnings = [];
  }

  check(program: Program): void {
    this.errors = [];
    this.warnings = [];
    this.symbolTable.clear();

    this.checkStatements(program.statements);
  }

  private checkStatements(statements: ASTNode[]): void {
    for (const stmt of statements) {
      this.checkStatement(stmt);
    }
  }

  private checkStatement(stmt: ASTNode): void {
    if (isQueryNode(stmt)) {
      const varName = stmt.varName;
      this.define(varName, { type: 'Query', dimension: 768 });
    } else if (isEncodeNode(stmt)) {
      const inputVar = stmt.inputVar;
      const outputVar = stmt.outputVar;

      const inputType = this.lookup(inputVar);
      if (!inputType) {
        this.addError(`Variable '${inputVar}' is not defined`);
        return;
      }

      if (inputType.type !== 'Query') {
        this.addWarning(
          `Encode expects Query type, got ${inputType.type} for '${inputVar}'`
        );
      }

      this.define(outputVar, { type: 'Latent', dimension: 512 });
    } else if (isPathNode(stmt)) {
      const inputVar = stmt.inputVar;
      const outputVar = stmt.outputVar;
      const pathType = stmt.pathType;

      const inputType = this.lookup(inputVar);
      if (!inputType) {
        this.addError(`Variable '${inputVar}' is not defined`);
        return;
      }

      if (inputType.type !== 'Latent') {
        this.addError(
          `Path expects Latent type, got ${inputType.type} for '${inputVar}'`
        );
        return;
      }

      this.define(outputVar, {
        type: 'Path',
        dimension: 512,
        constraints: [pathType],
      });
    } else if (isWeightNode(stmt)) {
      if (stmt.weights) {
        const { alpha, beta, gamma } = stmt.weights;

        if (alpha < 0 || alpha > 1 || beta < 0 || beta > 1 || gamma < 0 || gamma > 1) {
          this.addError(
            `Weight values must be in [0, 1], got α=${alpha}, β=${beta}, γ=${gamma}`
          );
          return;
        }

        const sum = alpha + beta + gamma;
        if (Math.abs(sum - 1.0) > 1e-6) {
          this.addError(
            `Weight simplex constraint violated: α + β + γ = ${sum}, expected 1.0`
          );
          return;
        }

        this.define('weights', {
          type: 'Weight',
          constraints: ['simplex', 'normalized'],
        });
      }
    } else if (isEnsembleNode(stmt)) {
      const [path1, path2, path3] = stmt.pathVars;
      const weightsVar = stmt.weightsVar;
      const outputVar = stmt.outputVar;

      const pathVars = [path1, path2, path3];
      for (const pathVar of pathVars) {
        const pathType = this.lookup(pathVar);
        if (!pathType) {
          this.addError(`Variable '${pathVar}' is not defined`);
          return;
        }
        if (pathType.type !== 'Path') {
          this.addError(
            `Ensemble expects Path type, got ${pathType.type} for '${pathVar}'`
          );
          return;
        }
      }

      const weightType = this.lookup(weightsVar);
      if (!weightType) {
        this.addWarning(`Weight variable '${weightsVar}' not found, assuming default weights`);
      } else if (weightType.type !== 'Weight') {
        this.addError(
          `Ensemble expects Weight type, got ${weightType.type} for '${weightsVar}'`
        );
        return;
      }

      this.define(outputVar, {
        type: 'Ensemble',
        dimension: 512,
        constraints: ['composite'],
      });
    } else if (isCritiqueNode(stmt)) {
      const inputVar = stmt.inputVar;
      const outputVar = stmt.outputVar;

      const inputType = this.lookup(inputVar);
      if (!inputType) {
        this.addError(`Variable '${inputVar}' is not defined`);
        return;
      }

      if (inputType.type !== 'Ensemble') {
        this.addWarning(
          `Critique typically takes Ensemble input, got ${inputType.type} for '${inputVar}'`
        );
      }

      this.define(outputVar, {
        type: 'Critique',
        constraints: ['range', '[-1, 1]'],
      });
    } else if (isSampleNode(stmt)) {
      const inputVar = stmt.inputVar;
      const outputVar = stmt.outputVar;
      const threshold = stmt.threshold;

      const inputType = this.lookup(inputVar);
      if (!inputType) {
        this.addError(`Variable '${inputVar}' is not defined`);
        return;
      }

      if (threshold !== undefined) {
        if (threshold < 0 || threshold > 1) {
          this.addError(
            `Sampling threshold must be in [0, 1], got ${threshold}`
          );
          return;
        }
      }

      this.define(outputVar, {
        type: 'Output',
        constraints: ['token', 'vocabulary'],
      });
    } else if (isDetokenizeNode(stmt)) {
      const inputVar = stmt.inputVar;
      const outputVar = stmt.outputVar;

      const inputType = this.lookup(inputVar);
      if (!inputType) {
        this.addError(`Variable '${inputVar}' is not defined`);
        return;
      }

      this.define(outputVar, {
        type: 'Output',
        constraints: ['string', 'korean'],
      });
    }
  }

  private define(name: string, type: TypeInfo): void {
    this.symbolTable.set(name, type);
  }

  private lookup(name: string): TypeInfo | null {
    const type = this.symbolTable.get(name);
    return type || null;
  }

  private addError(message: string): void {
    this.errors.push(message);
  }

  private addWarning(message: string): void {
    this.warnings.push(message);
  }

  getErrors(): string[] {
    return this.errors;
  }

  getWarnings(): string[] {
    return this.warnings;
  }

  getSymbolTable(): Map<string, TypeInfo> {
    return new Map(this.symbolTable);
  }

  getTypeOf(name: string): MindLangType | null {
    const info = this.lookup(name);
    return info ? info.type : null;
  }

  isValid(): boolean {
    return this.errors.length === 0;
  }
}

export function check(program: Program): {
  valid: boolean;
  errors: string[];
  warnings: string[];
  symbolTable: Map<string, TypeInfo>;
} {
  const checker = new Checker();
  checker.check(program);

  return {
    valid: checker.isValid(),
    errors: checker.getErrors(),
    warnings: checker.getWarnings(),
    symbolTable: checker.getSymbolTable(),
  };
}

export function typeInference(program: Program): Map<string, TypeInfo> {
  const checker = new Checker();
  checker.check(program);
  return checker.getSymbolTable();
}

export function validateConstraints(program: Program): {
  valid: boolean;
  errors: string[];
} {
  const checker = new Checker();
  checker.check(program);

  return {
    valid: checker.isValid(),
    errors: checker.getErrors(),
  };
}

